import React from 'react';

function App() {
  return (
    <div style={{ padding: '50px', fontFamily: 'sans-serif' }}>
      <h1 style={{ color: 'red', fontSize: '40px' }}>
        TEST RÉUSSI ! C'EST BIEN CE FICHIER !
      </h1>
      <p>Si tu vois ce texte rouge, on tient le bon fichier.</p>
      <p>Si tu vois toujours l'écran noir, alors ton projet utilise un autre fichier App.js quelque part.</p>
    </div>
  );
}

export default App;
